  transmute(spine_id, in_ato = TRUE) |&gt;
  full_join(dhda_sp_db |&gt; transmute(spine_id, in_dhda = TRUE), by = "spine_id") |&gt;
  mutate(in_ato  = coalesce(in_ato,  FALSE),
         in_dhda = coalesce(in_dhda, FALSE)) |&gt;
  count(in_ato, in_dhda) |&gt;
  collect()
